import React from "react";

function MovieItem({ movie, onSelect }) {
    // This constant holds a professional grey placeholder image
    const placeholderImage = "https://via.placeholder.com/300x450?text=No+Poster+Available";

    return (
        <li className="movie-card" onClick={() => onSelect(movie)}>
            <img
                src={
                    movie.poster && movie.poster !== "N/A"
                        ? movie.poster
                        : placeholderImage
                }
                alt={movie.title}
                /* This 'onError' handles cases where the link exists but is actually broken */
                onError={(e) => { e.target.src = placeholderImage; }}
            />
            <div className="movie-card-overlay">
                <div className="movie-card-title">{movie.title}</div>
            </div>
        </li>
    );
}

export default MovieItem;
